input.command:
KC=/mydata/karma/runs/short/r7/elasticsearch-bootstrap-to-production-adversary-20260703_090146/bundle/kubeconfig

# Patch the StatefulSet to add http-certs and file-realm volume mounts
kubectl --kubeconfig=$KC -n elasticsearch patch statefulset es-cluster --type=json -p='[
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "http-certs",
      "secret": {
        "secretName": "es-http-tls"
      }
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "file-realm",
      "secret": {
        "secretName": "es-file-realm-aggregate",
        "items": [
          {"key": "users", "path": "users"},
          {"key": "users_roles", "path": "users_roles"},
          {"key": "roles.yml", "path": "roles.yml"}
        ]
      }
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "http-certs",
      "mountPath": "/usr/share/elasticsearch/config/http-certs",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "file-realm",
      "mountPath": "/usr/share/elasticsearch/config/users",
      "subPath": "users",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "file-realm",
      "mountPath": "/usr/share/elasticsearch/config/users_roles",
      "subPath": "users_roles",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "file-realm",
      "mountPath": "/usr/share/elasticsearch/config/roles.yml",
      "subPath": "roles.yml",
      "readOnly": true
    }
  }
]'
echo "StatefulSet patched"

